+    const audits = db
+      .prepare(
+        `SELECT action, entity_type, entity_id, before_json, after_json
+         FROM audit_logs
+         WHERE entity_type = ?
+         ORDER BY id ASC`,
+      )
+      .all('business_profile') as Array<{
+      action: string;
+      entity_type: string;
+      entity_id: string;
+      before_json: string | null;
+      after_json: string | null;
