+    .prepare(
+      `SELECT id, trade_name, legal_name_public_policy, business_start_date, tax_office,
+              blue_return_enabled, invoice_registration_number, created_at, updated_at
+       FROM business_profiles
+       ORDER BY id ASC`,
+    )
