+      });
+
+      profile.get<{ Params: ProfileParams }>('/:id', async (req, reply) => {
+        const id = parseId(req.params.id);
+        if (id == null) {
+          reply.code(400);
+          return { error: 'invalid_id' };
+        }
+        const result = getProfile(app.db, id);
+        if (!result) {
