+          reply.code(400);
+          return { error: 'invalid_id' };
+        }
+        const before = getProfile(app.db, id);
+        if (!before) {
+          reply.code(404);
+          return { error: 'not_found' };
+        }
+        app.db.transaction(() => {
+          app.db.prepare('DELETE FROM business_profiles WHERE id = ?').run(id);
+          writeAudit(app.db, {
+            action: 'delete',
+            entityType: 'business_profile',
+            entityId: id,
