      .prepare('SELECT * FROM obligations ORDER BY due_date IS NULL, due_date ASC, id ASC')
      .all()
      .map((row) => {
        const obligation = mapRow(row as ObligationRow);
        return { ...obligation, dueStatus: dueStatus(obligation.dueDate, today) };
