+
+interface BusinessProfile {
+  id: number;
+  tradeName: string;
+  legalNamePublicPolicy: string;
+  businessStartDate: string | null;
+  taxOffice: string | null;
+  blueReturnEnabled: boolean;
+  invoiceRegistrationNumber: string | null;
