+        }
+
+        try {
+          const body = req.body ?? {};
+          const params = {
+            id,
+            hasTradeName: body.tradeName === undefined ? 0 : 1,
+            tradeName: body.tradeName === undefined ? null : parseRequiredString(body.tradeName, 'tradeName'),
