+            }
+            writeAudit(app.db, {
+              action: 'update',
+              entityType: 'business_profile',
+              entityId: id,
+              before,
+              after,
+            });
+            return after;
+          })();
+          return updated;
+        } catch (error) {
+          reply.code(400);
+          return { error: 'invalid_payload', message: error instanceof Error ? error.message : 'invalid payload' };
+        }
+      });
+
+      profile.delete<{ Params: ProfileParams }>('/:id', async (req, reply) => {
